'use client';

import { useState } from 'react';
import Link from 'next/link';
import { signIn } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import styles from './auth.module.css';

export default function SignIn() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setIsLoading(true);

        try {
            const result = await signIn('credentials', {
                email,
                password,
                redirect: false,
            });

            if (result?.error) {
                setError('Fel e-post eller lösenord');
                return;
            }

            // Fetch session to determine role-based redirect
            try {
                const res = await fetch('/api/auth/session');
                if (res.ok) {
                    const session = await res.json();
                    const role = session?.user?.role;

                    if (role === 'COACH') {
                        router.push('/coach/dashboard');
                        return;
                    }

                    if (role === 'ADMIN') {
                        router.push('/admin');
                        return;
                    }
                }
            } catch {
                // fall back to default route below
            }

            // Default behaviour for USER or unknown role
            router.push('/intake');
        } catch (err) {
            setError('Något gick fel. Försök igen.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className={styles.wrapper}>
            <img src="/branding/corner.png" className={`${styles.corner} ${styles.topRight}`} alt="" />
            <img src="/branding/corner.png" className={`${styles.corner} ${styles.bottomLeft}`} alt="" />

            <div className={styles.authCard}>
                <img src="/branding/heart.png" className={styles.miniHeart} alt="" />
                <h1>Välkommen tillbaka</h1>
                <p className={styles.subtitle}>Logga in på ditt konto</p>

                <form className={styles.form} onSubmit={handleSubmit}>
                    <input
                        type="email"
                        placeholder="E-post"
                        className={styles.input}
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                    />
                    <input
                        type="password"
                        placeholder="Lösenord"
                        className={styles.input}
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                    />

                    {error && <p className={styles.errorMessage}>{error}</p>}

                    <button
                        type="submit"
                        className={styles.submitBtn}
                        disabled={isLoading}
                        aria-busy={isLoading}
                        aria-live="polite"
                    >
                        {isLoading && <span className="spinner" style={{ marginRight: 8 }} aria-hidden="true" />}
                        {isLoading ? 'Loggar in...' : 'Logga in'}
                    </button>
                </form>

                <div className={styles.footerLinks}>
                    Ingen medlem än? <Link href="/register">Gå med nu</Link>
                    <br />
                    <Link href="/" className={styles.backLink}>Tillbaka till start</Link>
                </div>
            </div>
        </div>
    );
}
